'use client';

import { useState, useEffect, useCallback } from 'react';
import { 
  Calendar, 
  Clock, 
  Check, 
  X as CloseIcon, 
  AlertCircle,
  FileText,
  UserCheck,
  Send
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

interface LeaveRequest {
  id: string;
  leaveType: string;
  startDate: string;
  endDate: string;
  reason: string | null;
  approvalStatus: 'PENDING' | 'APPROVED' | 'REJECTED';
  createdAt: string;
  employee: {
    id: string;
    firstName: string;
    lastName: string;
    employeeCode: string;
    department: { name: string } | null;
    designation: { title: string } | null;
  };
}

export default function LeavesPage() {
  const { user } = useStore();
  const [requests, setRequests] = useState<LeaveRequest[]>([]);
  const [loading, setLoading] = useState(true);

  // New request form state
  const [leaveType, setLeaveType] = useState('Casual');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [reason, setReason] = useState('');
  const [formMsg, setFormMsg] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const fetchLeaves = useCallback(() => {
    setLoading(true);
    // If employee, only fetch their own leaves, otherwise fetch all
    const params: any = {};
    if (user?.role === 'EMPLOYEE' && user.employeeId) {
      params.employeeId = user.employeeId;
    }

    apiClient.get('/api/leaves', params)
      .then(res => {
        if (res.success) {
          setRequests(res.data);
        }
      })
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, [user]);

  useEffect(() => {
    fetchLeaves();
  }, [fetchLeaves]);

  const handleApply = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormMsg(null);

    if (!user?.employeeId) return;
    if (!startDate || !endDate) {
      setFormMsg({ type: 'error', text: 'Please fill in both start and end dates' });
      return;
    }

    try {
      const res = await apiClient.post('/api/leaves', {
        employeeId: user.employeeId,
        leaveType,
        startDate,
        endDate,
        reason
      });

      if (res.success) {
        setFormMsg({ type: 'success', text: 'Leave request submitted successfully!' });
        setStartDate('');
        setEndDate('');
        setReason('');
        fetchLeaves();
      } else {
        setFormMsg({ type: 'error', text: res.message || 'Failed to submit request' });
      }
    } catch (err: any) {
      setFormMsg({ type: 'error', text: err.message || 'Connection error occurred' });
    }
  };

  const handleReview = async (id: string, status: 'APPROVED' | 'REJECTED') => {
    try {
      const res = await apiClient.put(`/api/leaves/${id}`, { status });
      if (res.success) {
        fetchLeaves();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  const getDaysCount = (start: string, end: string) => {
    const s = new Date(start);
    const e = new Date(end);
    const diff = e.getTime() - s.getTime();
    return Math.round(diff / (1000 * 60 * 60 * 24)) + 1;
  };

  const isAdminOrHR = user?.role === 'ADMIN' || user?.role === 'HR';

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div>
        <h2 className="text-xl font-black text-[var(--text-primary)]">Leave Management</h2>
        <p className="text-xs text-[var(--text-muted)] mt-0.5">Submit leave applications and process employee approval requests</p>
      </div>

      {/* Main Grid Layout */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
        
        {/* Left Column: Leave application form (Employees) */}
        {!isAdminOrHR && (
          <div className="glass-card p-6 h-fit hover:transform-none">
            <h3 className="text-base font-bold text-[var(--text-primary)] mb-4">Request Leave</h3>
            
            {formMsg && (
              <div 
                className={`p-3 text-xs font-semibold rounded-xl border mb-4
                  ${formMsg.type === 'success' 
                    ? 'bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border-emerald-200/50' 
                    : 'bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border-red-200/50'
                  }
                `}
              >
                {formMsg.text}
              </div>
            )}

            <form onSubmit={handleApply} className="space-y-4">
              {/* Type */}
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Leave Type</label>
                <select
                  value={leaveType}
                  onChange={(e) => setLeaveType(e.target.value)}
                  className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                >
                  <option value="Casual">Casual Leave</option>
                  <option value="Sick">Sick Leave</option>
                  <option value="Maternity">Maternity Leave</option>
                  <option value="Paternity">Paternity Leave</option>
                  <option value="Unpaid">Unpaid Leave</option>
                </select>
              </div>

              {/* Date Inputs */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Start Date</label>
                  <input
                    type="date"
                    required
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">End Date</label>
                  <input
                    type="date"
                    required
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>
              </div>

              {/* Reason */}
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Reason / Description</label>
                <textarea
                  rows={3}
                  placeholder="Provide details about your leave request..."
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  className="w-full p-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500 resize-none"
                ></textarea>
              </div>

              {/* Apply Submit button */}
              <button
                type="submit"
                className="flex w-full h-10 items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-white font-bold text-xs shadow-md shadow-blue-600/10 active:scale-99 transition-all cursor-pointer"
              >
                <Send size={14} />
                Submit Application
              </button>
            </form>
          </div>
        )}

        {/* Right Column (Wide if Employee, full width if Admin): Leave Requests list */}
        <div className={`glass-card p-6 h-full hover:transform-none ${!isAdminOrHR ? 'lg:col-span-2' : 'lg:col-span-3'}`}>
          <h3 className="text-base font-bold text-[var(--text-primary)] mb-4">
            {isAdminOrHR ? 'Review Leave Requests' : 'Your Leave Applications'}
          </h3>

          <div className="space-y-4">
            {loading ? (
              <div className="py-12 text-center text-xs text-[var(--text-muted)]">
                <div className="flex flex-col items-center justify-center gap-2">
                  <div className="h-6 w-6 animate-spin rounded-full border-2 border-blue-200 border-t-blue-600"></div>
                  <span>Loading leave requests...</span>
                </div>
              </div>
            ) : requests.length === 0 ? (
              <div className="py-12 text-center text-xs text-[var(--text-muted)] font-medium">
                No leave requests found
              </div>
            ) : (
              requests.map((item) => {
                const days = getDaysCount(item.startDate, item.endDate);
                return (
                  <div 
                    key={item.id}
                    className="p-4 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] flex flex-col md:flex-row md:items-center justify-between gap-4 hover:border-slate-300 dark:hover:border-slate-700 transition-all"
                  >
                    {/* Details Column */}
                    <div className="space-y-2 flex-1">
                      <div className="flex flex-wrap items-center gap-2.5">
                        {isAdminOrHR && (
                          <span className="text-xs font-bold text-[var(--text-primary)]">
                            {item.employee.firstName} {item.employee.lastName} ({item.employee.employeeCode})
                          </span>
                        )}
                        <span className="inline-flex items-center rounded-full bg-blue-50 dark:bg-blue-950/20 px-2 py-0.5 text-[10px] font-bold text-blue-600 dark:text-blue-400 border border-blue-100 dark:border-blue-900/10">
                          {item.leaveType}
                        </span>
                        <span className="text-[10px] text-[var(--text-muted)] font-bold">
                          {days} {days === 1 ? 'day' : 'days'}
                        </span>
                      </div>
                      
                      {/* Dates */}
                      <div className="flex items-center gap-2 text-xs text-[var(--text-secondary)] font-medium">
                        <Calendar size={14} className="text-blue-500" />
                        <span>{formatDate(item.startDate)}</span>
                        <span>to</span>
                        <span>{formatDate(item.endDate)}</span>
                      </div>

                      {/* Reason */}
                      {item.reason && (
                        <p className="text-xs text-[var(--text-secondary)] italic bg-slate-50 dark:bg-slate-900/30 p-2.5 rounded-lg border border-[var(--card-border)]">
                          &ldquo;{item.reason}&rdquo;
                        </p>
                      )}
                    </div>

                    {/* Status / Review action Column */}
                    <div className="shrink-0 flex items-center justify-end gap-2.5">
                      {item.approvalStatus === 'PENDING' ? (
                        isAdminOrHR ? (
                          <div className="flex gap-2">
                            <button
                              onClick={() => handleReview(item.id, 'APPROVED')}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-xl bg-emerald-50 dark:bg-emerald-950/20 hover:bg-emerald-600 dark:hover:bg-emerald-500 border border-emerald-200/50 dark:border-emerald-900/10 text-emerald-600 dark:text-emerald-400 hover:text-white dark:hover:text-white transition-colors cursor-pointer"
                              title="Approve leave"
                            >
                              <Check size={16} />
                            </button>
                            <button
                              onClick={() => handleReview(item.id, 'REJECTED')}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-xl bg-rose-50 dark:bg-rose-950/20 hover:bg-rose-600 dark:hover:bg-rose-500 border border-rose-200/50 dark:border-rose-900/10 text-rose-600 dark:text-rose-400 hover:text-white dark:hover:text-white transition-colors cursor-pointer"
                              title="Reject leave"
                            >
                              <CloseIcon size={16} />
                            </button>
                          </div>
                        ) : (
                          <span className="inline-flex items-center gap-1 text-[10px] font-bold text-amber-500">
                            <Clock size={12} />
                            Pending Review
                          </span>
                        )
                      ) : (
                        <span 
                          className={`inline-flex items-center gap-1 rounded-full px-2.5 py-1 text-[10px] font-bold border
                            ${item.approvalStatus === 'APPROVED' 
                              ? 'bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/10' 
                              : 'bg-rose-50 dark:bg-rose-950/20 text-rose-600 dark:text-rose-400 border-rose-100 dark:border-rose-900/10'
                            }
                          `}
                        >
                          {item.approvalStatus === 'APPROVED' ? <Check size={10} /> : <AlertCircle size={10} />}
                          {item.approvalStatus}
                        </span>
                      )}
                    </div>

                  </div>
                );
              })
            )}
          </div>
        </div>

      </div>
    </div>
  );
}
